import { useState, useEffect, useCallback } from 'react';

export function useFetch<T>(url: string) {
  const [state, setState] = useState<{ data: T | null; loading: boolean; error: Error | null }>({ data: null, loading: true, error: null });
  const fetchData = useCallback(async (signal: AbortSignal) => {
    setState(s => ({ ...s, loading: true, error: null }));
    try {
      const res = await fetch(url, { signal });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json() as T;
      setState({ data, loading: false, error: null });
    } catch (e) {
      if ((e as Error).name === 'AbortError') return;
      setState(s => ({ ...s, loading: false, error: e as Error }));
    }
  }, [url]);
  useEffect(() => {
    const ctrl = new AbortController();
    fetchData(ctrl.signal);
    return () => ctrl.abort();
  }, [fetchData]);
  return { ...state, refetch: () => fetchData(new AbortController().signal) };
}

