import { useSyncExternalStore, useCallback } from 'react';

type CacheEntry<T> = { data?: T; error?: Error; promise?: Promise<void>; subscribers: Set<() => void> };
const cache = new Map<string, CacheEntry<any>>();

function getEntry<T>(key: string): CacheEntry<T> {
  if (!cache.has(key)) cache.set(key, { subscribers: new Set() });
  return cache.get(key)!;
}

async function load<T>(url: string, entry: CacheEntry<T>) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    entry.data = await res.json();
  } catch (e) { entry.error = e as Error; }
  finally { entry.promise = undefined; entry.subscribers.forEach(fn => fn()); }
}

export function useFetch<T>(url: string) {
  const entry = getEntry<T>(url);
  if (!entry.promise && !entry.data && !entry.error) entry.promise = load(url, entry);
  const subscribe = useCallback((cb: () => void) => { entry.subscribers.add(cb); return () => entry.subscribers.delete(cb); }, [entry]);
  useSyncExternalStore(subscribe, () => entry, () => entry);
  return { data: entry.data, error: entry.error, loading: !!entry.promise, refetch: () => { entry.promise = load(url, entry); } };
}

