// useFetch.ts - thin adapter over a query primitive
import { useSyncExternalStore } from 'react';
import { queryCache, type QueryKey, type QueryFn } from './queryCache';

export interface UseFetchOptions<T> { staleTime?: number; retry?: number; select?: (data: unknown) => T; }

export function useFetch<T>(key: QueryKey, fn: QueryFn<T>, opts: UseFetchOptions<T> = {}) {
  const query = queryCache.getOrCreate(key, fn, opts);
  useSyncExternalStore(query.subscribe, query.getSnapshot, query.getSnapshot);
  return { data: query.data as T | undefined, error: query.error, isLoading: query.state === 'loading', isStale: query.isStale(), refetch: query.refetch, invalidate: query.invalidate };
}

// Separation: useFetch is the HOOK. queryCache is the ENGINE.
// Engine handles: dedupe, cache, retry, stale-while-revalidate, GC, focus refetch.
// Hook handles: subscription + ergonomics.
// This split means engine is testable without React, hook is trivial.

