import { useState, useEffect, useRef } from 'react';

interface Options { leading?: boolean; maxWait?: number; }

export function useDebouncedValue<T>(value: T, delay: number, opts: Options = {}) {
  const [debounced, setDebounced] = useState(value);
  const lastInvoke = useRef(Date.now());
  const firstRender = useRef(true);
  useEffect(() => {
    if (firstRender.current && opts.leading) { setDebounced(value); firstRender.current = false; lastInvoke.current = Date.now(); return; }
    firstRender.current = false;
    const now = Date.now();
    const sinceLast = now - lastInvoke.current;
    const wait = opts.maxWait && sinceLast >= opts.maxWait ? 0 : delay;
    const t = setTimeout(() => { setDebounced(value); lastInvoke.current = Date.now(); }, wait);
    return () => clearTimeout(t);
  }, [value, delay, opts.leading, opts.maxWait]);
  return debounced;
}

