import { useState, useEffect, useRef, useCallback, useMemo } from 'react';

interface Options { leading?: boolean; maxWait?: number; equals?: <T>(a: T, b: T) => boolean; }

export function useDebouncedValue<T>(value: T, delay: number, opts: Options = {}) {
  const [debounced, setDebounced] = useState(value);
  const [isPending, setIsPending] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout>>();
  const maxTimer = useRef<ReturnType<typeof setTimeout>>();
  const eq = opts.equals ?? Object.is;
  const flush = useCallback(() => { clearTimeout(timer.current); clearTimeout(maxTimer.current); setDebounced(value); setIsPending(false); }, [value]);
  const cancel = useCallback(() => { clearTimeout(timer.current); clearTimeout(maxTimer.current); setIsPending(false); }, []);
  useEffect(() => {
    if (eq(value, debounced)) return;
    setIsPending(true);
    timer.current = setTimeout(() => { setDebounced(value); setIsPending(false); clearTimeout(maxTimer.current); }, delay);
    if (opts.maxWait && !maxTimer.current) maxTimer.current = setTimeout(() => { setDebounced(value); setIsPending(false); clearTimeout(timer.current); maxTimer.current = undefined; }, opts.maxWait);
    return () => clearTimeout(timer.current);
  }, [value, delay, opts.maxWait, debounced, eq]);
  return useMemo(() => [debounced, { isPending, flush, cancel }] as const, [debounced, isPending, flush, cancel]);
}

