// Splits CONCEPT (debouncing a value) from MECHANISM (a debounced callback)
import { useState, useEffect } from 'react';
import { useDebouncedCallback } from './useDebouncedCallback';

export interface DebouncedValue<T> { value: T; isPending: boolean; flush: () => void; cancel: () => void; }

export function useDebouncedValue<T>(input: T, delay: number, opts?: { leading?: boolean; maxWait?: number; equals?: (a: T, b: T) => boolean }): DebouncedValue<T> {
  const [value, setValue] = useState(input);
  const [isPending, setIsPending] = useState(false);
  const cb = useDebouncedCallback((next: T) => { setValue(next); setIsPending(false); }, delay, opts);
  const eq = opts?.equals ?? Object.is;
  useEffect(() => {
    if (eq(input, value)) return;
    setIsPending(true);
    cb.invoke(input);
  }, [input, value, cb, eq]);
  return { value, isPending, flush: () => cb.flush(), cancel: () => { cb.cancel(); setIsPending(false); } };
}

// useDebouncedValue is built FROM useDebouncedCallback.
// useDebouncedCallback is the primitive. useDebouncedValue is a composition.
// Same primitive powers: useDebouncedEffect, useThrottledValue, useRafValue.

