import { useState, useEffect, useCallback, useRef } from 'react';

interface Options<T> { serialize?: (v: T) => string; deserialize?: (s: string) => T; validate?: (v: unknown) => v is T; storage?: Storage; }

export function useLocalStorage<T>(key: string, initial: T, opts: Options<T> = {}) {
  const { serialize = JSON.stringify, deserialize = JSON.parse, validate, storage } = opts;
  const getStore = () => storage ?? (typeof window !== 'undefined' ? window.localStorage : null);
  const read = useCallback((): T => {
    const s = getStore(); if (!s) return initial;
    try { const raw = s.getItem(key); if (!raw) return initial; const parsed = deserialize(raw); return validate && !validate(parsed) ? initial : parsed as T; } catch { return initial; }
  }, [key, initial, deserialize, validate]);
  const [value, setValue] = useState<T>(read);
  const keyRef = useRef(key);
  useEffect(() => { if (keyRef.current !== key) { keyRef.current = key; setValue(read()); } }, [key, read]);
  const set = useCallback((v: T | ((p: T) => T)) => {
    setValue(prev => {
      const next = typeof v === 'function' ? (v as (p: T) => T)(prev) : v;
      try { getStore()?.setItem(key, serialize(next)); } catch (e) { console.error(e); }
      return next;
    });
  }, [key, serialize]);
  useEffect(() => {
    const onStorage = (e: StorageEvent) => { if (e.key === key) setValue(read()); };
    window.addEventListener('storage', onStorage);
    return () => window.removeEventListener('storage', onStorage);
  }, [key, read]);
  return [value, set] as const;
}

