// Distinguishes STATE (in-memory) from PERSISTENCE (storage layer)
import { useSyncExternalStore, useCallback } from 'react';

interface Codec<T> { encode: (v: T) => string; decode: (s: string) => T; }
interface Adapter { get(k: string): string | null; set(k: string, v: string): void; subscribe(cb: () => void): () => void; }

const jsonCodec = <T>(): Codec<T> => ({ encode: JSON.stringify, decode: JSON.parse });
const localStorageAdapter: Adapter = {
  get: k => typeof window === 'undefined' ? null : window.localStorage.getItem(k),
  set: (k, v) => { typeof window !== 'undefined' && window.localStorage.setItem(k, v); },
  subscribe: cb => { if (typeof window === 'undefined') return () => {}; window.addEventListener('storage', cb); return () => window.removeEventListener('storage', cb); },
};

export function usePersistentState<T>(key: string, initial: T, opts: { codec?: Codec<T>; adapter?: Adapter; validate?: (v: unknown) => v is T } = {}) {
  const { codec = jsonCodec<T>(), adapter = localStorageAdapter, validate } = opts;
  const getSnapshot = useCallback(() => {
    const raw = adapter.get(key); if (!raw) return initial;
    try { const v = codec.decode(raw); return validate && !validate(v) ? initial : v; } catch { return initial; }
  }, [key, adapter, codec, validate, initial]);
  const value = useSyncExternalStore(adapter.subscribe, getSnapshot, () => initial);
  const set = useCallback((v: T | ((p: T) => T)) => {
    const prev = getSnapshot(); const next = typeof v === 'function' ? (v as (p: T) => T)(prev) : v;
    adapter.set(key, codec.encode(next));
  }, [key, adapter, codec, getSnapshot]);
  return [value, set] as const;
}

// Renamed to usePersistentState. localStorage is just ONE adapter.
// Same hook works with sessionStorage, IndexedDB, cookie, in-memory test storage.

