import { useState, FormEvent, useRef } from 'react';
import { z } from 'zod';

const schema = z.object({ email: z.string().email(), password: z.string().min(8) });

export function LoginForm({ onSuccess }: { onSuccess: () => void }) {
  const [values, setValues] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitError, setSubmitError] = useState('');
  const [loading, setLoading] = useState(false);
  const emailRef = useRef<HTMLInputElement>(null);
  const submit = async (e: FormEvent) => {
    e.preventDefault();
    const parsed = schema.safeParse(values);
    if (!parsed.success) { setErrors(Object.fromEntries(parsed.error.issues.map(i => [i.path[0], i.message]))); emailRef.current?.focus(); return; }
    setLoading(true); setSubmitError('');
    try {
      const res = await fetch('/api/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(parsed.data) });
      if (!res.ok) throw new Error('Invalid credentials');
      onSuccess();
    } catch (e) { setSubmitError((e as Error).message); } finally { setLoading(false); }
  };
  return (
    <form onSubmit={submit} className="space-y-3" noValidate>
      <label className="block"><span>Email</span><input ref={emailRef} type="email" aria-invalid={!!errors.email} aria-describedby={errors.email && 'email-err'} value={values.email} onChange={e => setValues(v => ({ ...v, email: e.target.value }))} className="border p-2 w-full" /></label>
      {errors.email && <p id="email-err" className="text-red-500 text-sm">{errors.email}</p>}
      <label className="block"><span>Password</span><input type="password" aria-invalid={!!errors.password} value={values.password} onChange={e => setValues(v => ({ ...v, password: e.target.value }))} className="border p-2 w-full" /></label>
      {errors.password && <p className="text-red-500 text-sm">{errors.password}</p>}
      {submitError && <p role="alert" className="text-red-500">{submitError}</p>}
      <button disabled={loading} className="bg-blue-500 text-white px-4 py-2 disabled:opacity-50">{loading ? 'Logging in...' : 'Log in'}</button>
    </form>
  );
}

