import { useState } from 'react';
import { z } from 'zod';

const step1 = z.object({ email: z.string().email() });
const step2 = z.object({ company: z.string().min(1) });
const step3 = z.object({ plan: z.enum(['free', 'pro']) });
const schemas = [step1, step2, step3];

type Data = z.infer<typeof step1> & z.infer<typeof step2> & z.infer<typeof step3>;

export function SignupWizard() {
  const [step, setStep] = useState(0);
  const [data, setData] = useState<Partial<Data>>(() => { try { return JSON.parse(sessionStorage.getItem('signup') ?? '{}'); } catch { return {}; } });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const update = (patch: Partial<Data>) => { const next = { ...data, ...patch }; setData(next); sessionStorage.setItem('signup', JSON.stringify(next)); };
  const next = () => {
    const result = schemas[step].safeParse(data);
    if (!result.success) { setErrors(Object.fromEntries(result.error.issues.map(i => [i.path[0], i.message]))); return; }
    setErrors({}); setStep(s => s + 1);
  };
  const submit = async () => { await fetch('/api/signup', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) }); sessionStorage.removeItem('signup'); };
  const steps = [
    <input key="e" type="email" value={data.email ?? ''} onChange={e => update({ email: e.target.value })} aria-invalid={!!errors.email} className="border p-2 w-full" />,
    <input key="c" value={data.company ?? ''} onChange={e => update({ company: e.target.value })} aria-invalid={!!errors.company} className="border p-2 w-full" />,
    <select key="p" value={data.plan ?? ''} onChange={e => update({ plan: e.target.value as 'free' | 'pro' })} className="border p-2 w-full"><option value="">Pick</option><option value="free">Free</option><option value="pro">Pro</option></select>,
  ];
  return (<div className="max-w-md mx-auto p-6"><div className="mb-4">Step {step+1} of {steps.length}</div>{steps[step]}{Object.values(errors).map(e => <p key={e} className="text-red-500">{e}</p>)}<div className="mt-4 flex justify-between">{step > 0 && <button onClick={() => setStep(s => s-1)}>Back</button>}{step < steps.length-1 ? <button onClick={next}>Next</button> : <button onClick={submit}>Sign up</button>}</div></div>);
}

