// State machine for the flow + composable step API. URL is the source of truth.
import { useMachine } from '@xstate/react';
import { signupMachine } from './signupMachine';
import { useSearchParams, useRouter } from 'next/navigation';
import { stepRegistry } from './steps';

export function SignupWizard() {
  const [state, send] = useMachine(signupMachine, { input: { onComplete: (data) => fetch('/api/signup', { method: 'POST', body: JSON.stringify(data) }) } });
  const params = useSearchParams(); const router = useRouter();
  const stepId = params.get('step') ?? state.context.currentStepId;
  const Step = stepRegistry[stepId];
  return (
    <div className="max-w-md mx-auto p-6">
      <progress value={state.context.progress} max={1} className="w-full" />
      <Step
        value={state.context.data}
        onChange={(patch) => send({ type: 'PATCH', patch })}
        error={state.context.error}
      />
      <nav className="flex justify-between mt-4">
        {state.can({ type: 'BACK' }) && <button onClick={() => { send({ type: 'BACK' }); router.push(`?step=${state.context.prevStepId}`); }}>Back</button>}
        <button onClick={() => send({ type: 'NEXT' })} disabled={state.matches('validating')}>{state.matches('final') ? 'Finish' : 'Next'}</button>
      </nav>
    </div>
  );
}

// Principle: a wizard IS a state machine. Modeling it as one makes invalid states unrepresentable:
// - Cant be both 'validating' and 'showing error'
// - Cant skip steps that arent reachable from current state
// - URL syncs to state, refresh-safe, shareable, back-button works

