import { useState, useCallback, useRef } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { useRovingFocus } from './useRovingFocus';

interface Email { id: string; subject: string; }

export function EmailList({ emails }: { emails: Email[] }) {
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [anchor, setAnchor] = useState<number | null>(null);
  const parentRef = useRef<HTMLDivElement>(null);
  const v = useVirtualizer({ count: emails.length, getScrollElement: () => parentRef.current, estimateSize: () => 48, overscan: 8 });
  const roving = useRovingFocus(emails.length);
  const onSelect = useCallback((idx: number, e: { shiftKey: boolean }) => {
    setSelected(prev => {
      const n = new Set(prev);
      if (e.shiftKey && anchor !== null) {
        const [a, b] = anchor < idx ? [anchor, idx] : [idx, anchor];
        for (let i = a; i <= b; i++) n.add(emails[i].id);
      } else { const id = emails[idx].id; n.has(id) ? n.delete(id) : n.add(id); setAnchor(idx); }
      return n;
    });
  }, [emails, anchor]);
  return (
    <div ref={parentRef} className="h-[600px] overflow-auto" role="listbox" aria-multiselectable {...roving.containerProps}>
      <div style={{ height: v.getTotalSize(), position: 'relative' }}>
        {v.getVirtualItems().map(item => { const e = emails[item.index]; const sel = selected.has(e.id); return (
          <div key={e.id} role="option" aria-selected={sel} {...roving.itemProps(item.index)} onClick={ev => onSelect(item.index, ev)}
            style={{ position: 'absolute', top: item.start, height: item.size, width: '100%' }}
            className={`p-2 ${sel ? 'bg-blue-100' : ''}`}>{e.subject}</div>
        ); })}
      </div>
    </div>
  );
}

