import { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';

export function Modal({ open, onClose, labelledBy, children }: { open: boolean; onClose: () => void; labelledBy?: string; children: React.ReactNode }) {
  const dialogRef = useRef<HTMLDivElement>(null);
  const returnFocus = useRef<HTMLElement | null>(null);
  useEffect(() => {
    if (!open) return;
    returnFocus.current = document.activeElement as HTMLElement;
    const dialog = dialogRef.current!;
    const focusable = dialog.querySelectorAll<HTMLElement>('a[href], button, input, [tabindex]:not([tabindex="-1"])');
    focusable[0]?.focus();
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'Tab' && focusable.length) {
        const first = focusable[0], last = focusable[focusable.length - 1];
        if (e.shiftKey && document.activeElement === first) { last.focus(); e.preventDefault(); }
        else if (!e.shiftKey && document.activeElement === last) { first.focus(); e.preventDefault(); }
      }
    };
    document.addEventListener('keydown', onKey);
    document.body.style.overflow = 'hidden';
    return () => { document.removeEventListener('keydown', onKey); document.body.style.overflow = ''; returnFocus.current?.focus(); };
  }, [open, onClose]);
  if (!open) return null;
  return createPortal(
    <div onClick={onClose} className="fixed inset-0 bg-black/50 grid place-items-center z-50">
      <div ref={dialogRef} onClick={e => e.stopPropagation()} role="dialog" aria-modal="true" aria-labelledby={labelledBy} className="bg-white p-6 rounded shadow-lg max-w-md w-full">
        {children}
      </div>
    </div>,
    document.body
  );
}

