import { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import FocusTrap from 'focus-trap-react';

interface Props { open: boolean; onClose: () => void; title: string; children: React.ReactNode; size?: 'sm' | 'md' | 'lg'; }

export function Modal({ open, onClose, title, children, size = 'md' }: Props) {
  const headingId = useRef(`m-${Math.random().toString(36).slice(2)}`).current;
  useEffect(() => {
    if (!open) return;
    document.body.style.overflow = 'hidden';
    // Mark siblings inert so SRs ignore background
    const root = document.getElementById('__next') ?? document.body.firstElementChild;
    root?.setAttribute('inert', '');
    return () => { document.body.style.overflow = ''; root?.removeAttribute('inert'); };
  }, [open]);
  if (typeof window === 'undefined' || !open) return null;
  const sizes = { sm: 'max-w-sm', md: 'max-w-md', lg: 'max-w-2xl' };
  return createPortal(
    <FocusTrap focusTrapOptions={{ escapeDeactivates: false, clickOutsideDeactivates: false, returnFocusOnDeactivate: true }}>
      <div className="fixed inset-0 z-50 grid place-items-center">
        <div className="absolute inset-0 bg-black/50 animate-in fade-in" onClick={onClose} />
        <div role="dialog" aria-modal="true" aria-labelledby={headingId}
          onKeyDown={e => e.key === 'Escape' && onClose()}
          className={`relative bg-white rounded shadow-lg w-full ${sizes[size]} p-6 animate-in zoom-in-95`}>
          <h2 id={headingId} className="text-lg font-semibold mb-4">{title}</h2>
          {children}
        </div>
      </div>
    </FocusTrap>,
    document.body
  );
}

