import { useState, useMemo } from 'react';

interface Customer { id: string; name: string; createdAt: string; revenue: number; }
type SortKey = keyof Customer; type Dir = 'asc' | 'desc';

export function CustomerTable({ rows }: { rows: Customer[] }) {
  const [sort, setSort] = useState<{ key: SortKey; dir: Dir }>({ key: 'name', dir: 'asc' });
  const [page, setPage] = useState(0); const pageSize = 25;
  const sorted = useMemo(() => [...rows].sort((a, b) => { const m = sort.dir === 'asc' ? 1 : -1; return a[sort.key] > b[sort.key] ? m : -m; }), [rows, sort]);
  const paged = sorted.slice(page * pageSize, (page + 1) * pageSize);
  const toggle = (k: SortKey) => setSort(s => s.key === k ? { key: k, dir: s.dir === 'asc' ? 'desc' : 'asc' } : { key: k, dir: 'asc' });
  return (
    <div>
      <table className="w-full">
        <thead><tr>{(['name','createdAt','revenue'] as SortKey[]).map(k => <th key={k} onClick={() => toggle(k)} className="cursor-pointer">{k} {sort.key === k && (sort.dir === 'asc' ? '↑' : '↓')}</th>)}</tr></thead>
        <tbody>{paged.map(r => <tr key={r.id}><td>{r.name}</td><td>{r.createdAt}</td><td>{r.revenue}</td></tr>)}</tbody>
      </table>
      <button onClick={() => setPage(p => p-1)} disabled={page === 0}>Prev</button><button onClick={() => setPage(p => p+1)}>Next</button>
    </div>
  );
}

