import { useState, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';

interface Column<T> { key: keyof T; label: string; sortable?: boolean; render?: (row: T) => React.ReactNode; }
interface PageResult<T> { rows: T[]; total: number; }

export function DataTable<T extends { id: string }>({ columns, fetcher }: { columns: Column<T>[]; fetcher: (params: { sort?: string; dir?: string; page: number; pageSize: number }) => Promise<PageResult<T>> }) {
  const [sort, setSort] = useState<{ key: keyof T; dir: 'asc' | 'desc' } | null>(null);
  const [page, setPage] = useState(0); const pageSize = 25;
  const params = useMemo(() => ({ sort: sort?.key as string, dir: sort?.dir, page, pageSize }), [sort, page]);
  const { data, isLoading } = useQuery({ queryKey: ['table', params], queryFn: () => fetcher(params), placeholderData: prev => prev });
  return (
    <div>
      <table className="w-full"><thead><tr>{columns.map(c => (
        <th key={String(c.key)} aria-sort={sort?.key === c.key ? sort.dir === 'asc' ? 'ascending' : 'descending' : 'none'}
            onClick={() => c.sortable && setSort(s => s?.key === c.key ? { key: c.key, dir: s.dir === 'asc' ? 'desc' : 'asc' } : { key: c.key, dir: 'asc' })}
            className={c.sortable ? 'cursor-pointer' : ''}>{c.label}</th>
      ))}</tr></thead>
      <tbody>{isLoading ? <tr><td colSpan={columns.length}>Loading...</td></tr> : data?.rows.map(r => <tr key={r.id}>{columns.map(c => <td key={String(c.key)}>{c.render ? c.render(r) : String(r[c.key])}</td>)}</tr>)}</tbody></table>
      <div>Page {page+1} of {data ? Math.ceil(data.total / pageSize) : 1}<button onClick={() => setPage(p => Math.max(0, p-1))}>Prev</button><button onClick={() => setPage(p => p+1)} disabled={data && (page+1)*pageSize >= data.total}>Next</button></div>
    </div>
  );
}

