import { useQuery } from '@tanstack/react-query';
import { parseAsString, parseAsInteger, useQueryStates } from 'nuqs';

export function DataTable<T extends { id: string }>({ columns, fetcher }: { columns: ColumnDef<T>[]; fetcher: (p: { sort?: string; dir?: string; page: number; pageSize: number; filter?: string }) => Promise<{ rows: T[]; total: number }> }) {
  const [state, setState] = useQueryStates({ sort: parseAsString, dir: parseAsString, page: parseAsInteger.withDefault(0), filter: parseAsString.withDefault('') });
