  const query = useQuery({ queryKey: ['table', state], queryFn: () => fetcher({ ...state, sort: state.sort ?? undefined, dir: state.dir ?? undefined, pageSize }), placeholderData: p => p });
  const table = useReactTable({ data: query.data?.rows ?? [], columns, getCoreRowModel: getCoreRowModel(), manualSorting: true, manualPagination: true, pageCount: Math.ceil((query.data?.total ?? 0) / pageSize) });
  return (
    <div>
      <input value={state.filter} onChange={e => setState({ filter: e.target.value, page: 0 })} placeholder="Filter" className="border p-2" />
