// Table is a HEADLESS data primitive + slots. Visual table is composed in the feature.
import { useDataTable, type ColumnDef } from '@/data/useDataTable';
import { TableShell, TableHead, TableBody, TableRow, TableCell, Toolbar, Pagination } from '@/ui/table';

interface Customer { id: string; name: string; createdAt: string; revenue: number; }
const columns: ColumnDef<Customer>[] = [
  { id: 'name', header: 'Name', accessor: r => r.name, sortable: true, filterable: 'text' },
  { id: 'createdAt', header: 'Created', accessor: r => new Date(r.createdAt).toLocaleDateString(), sortable: true, filterable: 'dateRange' },
  { id: 'revenue', header: 'Revenue', accessor: r => `$${r.revenue.toLocaleString()}`, sortable: true, filterable: 'numberRange', align: 'right' },
];

export function CustomerTable() {
  const table = useDataTable<Customer>({ columns, queryKey: ['customers'], endpoint: '/api/customers', urlSync: true });
  return (
    <TableShell>
      <Toolbar table={table} />
      <TableHead table={table} />
      <TableBody table={table} renderRow={row => <TableRow key={row.id}>{row.cells.map(c => <TableCell key={c.id} align={c.column.align}>{c.value}</TableCell>)}</TableRow>} />
      <Pagination table={table} />
    </TableShell>
  );
}

// Principle: a table has many concerns (sort, filter, page, select, group, expand, resize). Separate them.
// useDataTable returns a model; UI components consume the model. Same model can drive a CSV export, a chart, a search page.

