import { useCombobox } from 'downshift';
import { useQuery } from '@tanstack/react-query';

export function SearchCombobox<T extends { id: string; name: string }>({ url, recentKey = 'recent_searches', maxRecent = 5 }: Props<T>) {
  const [q, setQ] = useState('');
  const [debouncedQ] = useDebouncedValue(q, 300);
  const [recent, setRecent] = useLocalStorage<string[]>(recentKey, []);

  const { data: results = [], isFetching } = useQuery<T[]>({
    queryKey: ['search', url, debouncedQ],
    queryFn: ({ signal }) => fetch(`${url}?${new URLSearchParams({ q: debouncedQ })}`, { signal }).then(r => r.json()),
    enabled: debouncedQ.length > 1,
    placeholderData: prev => prev
  });

  const items = debouncedQ.length < 2 ? recent.map(r => ({ id: r, name: r } as T)) : results;

  const combobox = useCombobox({
    items,
    inputValue: q,
    onInputValueChange: ({ inputValue }) => setQ(inputValue ?? ''),
    onSelectedItemChange: ({ selectedItem }) => {
      if (selectedItem) {
        setRecent([selectedItem.name, ...recent.filter(r => r !== selectedItem.name)].slice(0, maxRecent));
      }
    },
    itemToString: item => item?.name ?? ''
  });

  return (
    <div {...combobox.getRootProps({}, { suppressRefError: true })}>
      <input {...combobox.getInputProps({ 'aria-label': 'Search' })} />
      <ul {...combobox.getMenuProps()}>
