// Resumable chunked upload
class ChunkedUpload {
  private chunkSize = 5 * 1024 * 1024;
  async upload(file: File, onProgress: (n: number) => void) {
    const totalChunks = Math.ceil(file.size / this.chunkSize);
    const { uploadId } = await fetch('/api/upload/init', { method: 'POST', body: JSON.stringify({ name: file.name, size: file.size, totalChunks }) }).then(r => r.json());

    for (let i = 0; i < totalChunks; i++) {
      const chunk = file.slice(i * this.chunkSize, (i + 1) * this.chunkSize);
      const fd = new FormData();
      fd.append('chunk', chunk);
      fd.append('uploadId', uploadId);
      fd.append('chunkIndex', String(i));
      await this.uploadChunk(fd, 3);
      onProgress(((i + 1) / totalChunks) * 100);
    }
    return fetch('/api/upload/complete', { method: 'POST', body: JSON.stringify({ uploadId }) }).then(r => r.json());
  }
  private async uploadChunk(fd: FormData, retries: number): Promise<void> {
    for (let i = 0; i < retries; i++) {
      try {
        const r = await fetch('/api/upload/chunk', { method: 'POST', body: fd });
        if (r.ok) return;
      } catch {}
      await new Promise(r => setTimeout(r, 1000 * 2 ** i));
    }
    throw new Error('Chunk failed');
  }
}

