// Tus protocol resumable upload
import * as tus from 'tus-js-client';

export function ResumableUpload({ file, onComplete }: Props) {
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [upload, setUpload] = useState<tus.Upload | null>(null);
  const [status, setStatus] = useState<'idle' | 'uploading' | 'paused' | 'complete'>('idle');

  const start = () => {
    const upload = new tus.Upload(file, {
      endpoint: '/api/upload/tus',
      retryDelays: [0, 1000, 3000, 5000, 10000],
      metadata: { filename: file.name, filetype: file.type },
      onError: (err) => { setError(err.message); setStatus('idle'); },
      onProgress: (bytesUploaded, bytesTotal) => setProgress((bytesUploaded / bytesTotal) * 100),
      onSuccess: () => { setStatus('complete'); onComplete(upload.url!); }
    });
    upload.findPreviousUploads().then((prev) => {
      if (prev.length) upload.resumeFromPreviousUpload(prev[0]);
      upload.start();
      setUpload(upload);
      setStatus('uploading');
    });
  };

  const pause = () => { upload?.abort(); setStatus('paused'); };
  const resume = () => { upload?.start(); setStatus('uploading'); };

  return (
    <div>
      <progress value={progress} max={100} />
      <span>{Math.round(progress)}%</span>
      {status === 'idle' && <button onClick={start}>Upload</button>}
      {status === 'uploading' && <button onClick={pause}>Pause</button>}
      {status === 'paused' && <button onClick={resume}>Resume</button>}
      {error && <span role='alert'>{error}</span>}
    </div>
  );
}

