// Generic lightbox primitive with zoom, swipe, preload, fullscreen, share, captions, deep-linking via URL
import { useState, useEffect, useCallback, useRef } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import useEmblaCarousel from 'embla-carousel-react';

export function Lightbox<T extends { src: string; alt?: string; caption?: string }>({
  items, initialIndex = 0, open, onClose, queryParam, onIndexChange
}: LightboxProps<T>) {
  const [emblaRef, embla] = useEmblaCarousel({ startIndex: initialIndex });
  const [zoomed, setZoomed] = useState(false);
  const currentIdx = embla?.selectedScrollSnap() ?? initialIndex;

  // Deep-link via URL
  useEffect(() => {
    if (!open || !queryParam) return;
    const params = new URLSearchParams(window.location.search);
    params.set(queryParam, String(currentIdx));
    window.history.replaceState({}, '', `${window.location.pathname}?${params}`);
  }, [open, currentIdx, queryParam]);

  // Preload neighbors
  useEffect(() => {
    if (!embla) return;
    const preload = (i: number) => { new Image().src = items[i % items.length].src; };
    [currentIdx - 1, currentIdx + 1].forEach(i => preload((i + items.length) % items.length));
  }, [currentIdx, embla, items]);

  return (
    <Dialog.Root open={open} onOpenChange={(o) => !o && onClose()}>
      <Dialog.Portal>
        <Dialog.Overlay className='fixed inset-0 bg-black/95' />
        <Dialog.Content
          className='fixed inset-0 flex flex-col'
          onPointerDownOutside={(e) => zoomed && e.preventDefault()}
        >
          <div className='absolute top-4 right-4 flex gap-2 z-10'>
            <button onClick={() => setZoomed(z => !z)}>Zoom</button>
            <Dialog.Close>Close</Dialog.Close>
          </div>
          <div className='flex-1 overflow-hidden' ref={emblaRef}>
            <div className='flex h-full'>
              {items.map((item, i) => (
                <div key={i} className='flex-[0_0_100%] flex items-center justify-center'>
                  <img
                    src={item.src}
                    alt={item.alt ?? ''}
                    className={zoomed ? 'cursor-zoom-out' : 'cursor-zoom-in max-h-full max-w-full'}
                    onClick={() => setZoomed(z => !z)}
                  />
                </div>
              ))}
            </div>
          </div>
          {items[currentIdx]?.caption && (
            <div className='p-4 text-white text-center'>{items[currentIdx].caption}</div>
          )}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

