// Touch sensors + optimistic save
import { DndContext, KeyboardSensor, PointerSensor, TouchSensor, useSensor, useSensors, closestCenter } from '@dnd-kit/core';
import { sortableKeyboardCoordinates, SortableContext, arrayMove, verticalListSortingStrategy } from '@dnd-kit/sortable';

function useReorderableList<T extends { id: string }>(initial: T[], onSave: (items: T[]) => Promise<void>) {
  const [items, setItems] = useState(initial);
  const reorder = async (from: number, to: number) => {
    const next = arrayMove(items, from, to);
    setItems(next);  // optimistic
    try { await onSave(next); } catch { setItems(items); /* rollback */ }
  };
  return { items, reorder };
}

