import { DndContext, DragOverlay, useSensor, useSensors, PointerSensor, KeyboardSensor, MouseSensor, TouchSensor, closestCorners } from '@dnd-kit/core';
import { SortableContext, useSortable, sortableKeyboardCoordinates, arrayMove } from '@dnd-kit/sortable';

export function Kanban<T extends { id: string }>({ columns, items, onMove, announcer }: KanbanProps<T>) {
  const sensors = useSensors(
    useSensor(MouseSensor, { activationConstraint: { distance: 8 } }),
    useSensor(TouchSensor, { activationConstraint: { delay: 200, tolerance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const announcements = {
    onDragStart: ({ active }) => `Picked up ${active.id}`,
    onDragOver: ({ active, over }) => over ? `${active.id} over ${over.id}` : '',
    onDragEnd: ({ active, over }) => over ? `Dropped ${active.id} on ${over.id}` : `Dropped ${active.id}`,
    onDragCancel: ({ active }) => `Canceled ${active.id}`
  };

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCorners}
      accessibility={{ announcements }}
      onDragEnd={(e) => e.over && onMove(e.active.id as string, e.over.id as string)}
    >
      <div className='flex gap-4'>
        {columns.map(col => (
          <SortableContext key={col.id} items={items.filter(i => i.columnId === col.id).map(i => i.id)}>
            <Column col={col} items={items.filter(i => i.columnId === col.id)} />
          </SortableContext>
        ))}
      </div>
      <DragOverlay>{/* preview */}</DragOverlay>
    </DndContext>
  );
}

