// AnimatePresence + types + priorities
import { motion, AnimatePresence } from 'motion/react';

function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);
  const dismiss = useCallback((id: string) => {
    setToasts(t => t.filter(x => x.id !== id));
  }, []);
  const show = useCallback((opts: ToastOptions) => {
    const id = nanoid();
    const toast: Toast = { id, ...opts };
    setToasts(t => {
      const next = [...t, toast].sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0));
      return next.slice(0, 5);
    });
    if (opts.duration !== Infinity) {
      setTimeout(() => dismiss(id), opts.duration ?? 3000);
    }
    return id;
  }, [dismiss]);

  return (
    <ToastContext.Provider value={{ show, dismiss }}>
      {children}
      <div role='region' aria-live='polite' className='fixed top-4 right-4 space-y-2'>
        <AnimatePresence>
          {toasts.map(t => (
            <motion.div
              key={t.id}
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              drag='x'
              dragConstraints={{ left: 0, right: 0 }}
              onDragEnd={(_, info) => Math.abs(info.offset.x) > 100 && dismiss(t.id)}
            >
              {t.message}
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </ToastContext.Provider>
  );
}

