// Promise-aware toasts that integrate with React Query mutations
import { toast as sonnerToast } from 'sonner';  // production-grade lib

export function setupToasts() {
  return {
    promise: <T,>(promise: Promise<T>, opts: { loading: string; success: string | ((r: T) => string); error: string | ((e: Error) => string) }) => {
      return sonnerToast.promise(promise, opts);
    },
    success: (msg: string) => sonnerToast.success(msg),
    error: (msg: string) => sonnerToast.error(msg),
    info: (msg: string) => sonnerToast.info(msg),
    // Custom: integrate with mutations
    mutation: <T, V>(mutation: UseMutationResult<T, Error, V>) => {
      const original = mutation.mutate;
      mutation.mutate = (vars) => {
        const id = sonnerToast.loading('Saving...');
        original(vars, {
          onSuccess: () => sonnerToast.success('Saved', { id }),
          onError: (e) => sonnerToast.error(e.message, { id })
        });
      };
      return mutation;
    }
  };
}

