// Multi-tenant theme system with runtime token derivation
import { useEffect } from 'react';

type OKLCH = { l: number; c: number; h: number };

function deriveDarkVariant(light: OKLCH): OKLCH {
  // Perceptual lightness inversion
  return { l: Math.max(0.05, 1 - light.l + 0.05), c: light.c, h: light.h };
}

function setThemeTokens(brand: { primary: OKLCH; surface: OKLCH; text: OKLCH }, mode: 'light' | 'dark') {
  const root = document.documentElement;
  const apply = (key: string, value: OKLCH) => {
    const adjusted = mode === 'dark' ? deriveDarkVariant(value) : value;
    root.style.setProperty(`--color-${key}`, `oklch(${adjusted.l} ${adjusted.c} ${adjusted.h})`);
  };
  apply('primary', brand.primary);
  apply('surface', brand.surface);
  apply('text', brand.text);
}

export function useMultiBrandTheme(brand: BrandConfig) {
  const [mode, setMode] = useThemeMode();  // 'light' | 'dark' | 'system'

  useEffect(() => {
    const resolved = mode === 'system'
      ? (matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
      : mode;
    setThemeTokens(brand, resolved);
    document.documentElement.dataset.theme = resolved;
  }, [brand, mode]);

  return { mode, setMode };
}

