// Layered boundaries + circuit breakers + retry policies
class CircuitBreaker {
  private failures = 0;
  private openUntil = 0;
  constructor(private threshold = 5, private resetMs = 60000) {}
  async call<T>(fn: () => Promise<T>): Promise<T> {
    if (Date.now() < this.openUntil) throw new Error('Circuit open');
    try {
      const r = await fn();
      this.failures = 0;
      return r;
    } catch (e) {
      this.failures++;
      if (this.failures >= this.threshold) {
        this.openUntil = Date.now() + this.resetMs;
      }
      throw e;
    }
  }
}

const apiBreaker = new CircuitBreaker();
async function apiCall<T>(fn: () => Promise<T>) {
  return apiBreaker.call(fn);
}

