// Comprehensive error system with classification, recovery, observability
interface ErrorContext {
  userId?: string;
  feature?: string;
  retryCount?: number;
  fingerprint?: string;
}

class ErrorPipeline {
  constructor(
    private handlers: Array<(error: Error, ctx: ErrorContext) => Promise<'handled' | 'continue'>>,
    private telemetry: Telemetry
  ) {}

  async handle(error: Error, ctx: ErrorContext) {
    this.telemetry.record(error, ctx);
    for (const handler of this.handlers) {
      const result = await handler(error, ctx);
      if (result === 'handled') return;
    }
    throw error;  // unhandled
  }
}

const pipeline = new ErrorPipeline([
  // 401 → refresh + retry
  async (e, ctx) => {
    if (e instanceof AuthError && (ctx.retryCount ?? 0) === 0) {
      await refreshToken();
      return 'handled';
    }
    return 'continue';
  },
  // Network → backoff
  async (e, ctx) => {
    if (e instanceof NetworkError && (ctx.retryCount ?? 0) < 3) {
      await new Promise(r => setTimeout(r, 1000 * 2 ** (ctx.retryCount ?? 0)));
      return 'handled';
    }
    return 'continue';
  },
  // Validation → user feedback
  async (e) => {
    if (e instanceof ValidationError) {
      toast.error(e.message);
      return 'handled';
    }
    return 'continue';
  }
], { record: (error, ctx) => Sentry.captureException(error, { extra: ctx }) });

// Use
