import { trace, SpanStatusCode } from '@opentelemetry/api';

const tracer = trace.getTracer('frontend');

async function instrumented<T>(name: string, attributes: Record<string, string | number>, fn: () => Promise<T>): Promise<T> {
  return tracer.startActiveSpan(name, async (span) => {
    Object.entries(attributes).forEach(([k, v]) => span.setAttribute(k, v));
    try {
      const result = await fn();
      span.setStatus({ code: SpanStatusCode.OK });
      return result;
    } catch (e) {
      span.setStatus({ code: SpanStatusCode.ERROR, message: e instanceof Error ? e.message : 'Error' });
      span.recordException(e instanceof Error ? e : new Error(String(e)));
      throw e;
    } finally {
      span.end();
    }
  });
}

