// Versioned + migrated storage hook
function useVersionedStorage<T>(key: string, options: {
  defaultValue: T;
  schema: ZodSchema<T>;
  version: number;
  migrations?: Record<number, (old: unknown) => unknown>;
}) {
  const { defaultValue, schema, version, migrations = {} } = options;

  const read = useCallback((): T => {
    if (typeof window === 'undefined') return defaultValue;
    try {
      const raw = localStorage.getItem(key);
      if (!raw) return defaultValue;
      let parsed = JSON.parse(raw);
      const storedVersion = parsed.__version ?? 0;
      let data = parsed.data ?? parsed;

      // Run migrations
      for (let v = storedVersion + 1; v <= version; v++) {
        if (migrations[v]) data = migrations[v](data);
      }

      const validated = schema.parse(data);
      // Re-save migrated
      if (storedVersion < version) {
        localStorage.setItem(key, JSON.stringify({ __version: version, data: validated }));
      }
      return validated;
    } catch {
      localStorage.removeItem(key);  // corrupt - clean
      return defaultValue;
    }
  }, [key, defaultValue, schema, version, migrations]);

  const [value, setValue] = useState<T>(read);

  useEffect(() => {
    try { localStorage.setItem(key, JSON.stringify({ __version: version, data: value })); } catch {}
  }, [key, value, version]);

  return [value, setValue] as const;
}

// Usage with migration:
useVersionedStorage('settings', {
  defaultValue: { theme: 'light', notifications: true },
  schema: SettingsSchema,
  version: 2,
  migrations: {
    2: (old: any) => ({ ...old, notifications: old.notify ?? true })  // renamed field
  }
});

