// Domain-specific hooks with schema validation, observability, semantic invalidation
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { z, ZodSchema } from 'zod';

function createApiHook<T>(config: {
  schema: ZodSchema<T>;
  endpoint: (params: Record<string, string>) => string;
  tags?: string[];
}) {
  return function useApi(params: Record<string, string>) {
    return useQuery<T>({
      queryKey: ['api', config.endpoint(params), params],
      queryFn: async ({ signal }) => {
        const start = performance.now();
        const r = await fetch(config.endpoint(params), { signal, credentials: 'include' });
        if (!r.ok) {
          telemetry.error('api_error', { endpoint: config.endpoint(params), status: r.status });
          throw new ApiError(r.status, r.statusText);
        }
        const data = await r.json();
        telemetry.timing('api_latency', performance.now() - start, { endpoint: config.endpoint(params) });
        return config.schema.parse(data);
      },
      meta: { tags: config.tags }  // for invalidation
    });
  };
}

const UserSchema = z.object({ id: z.string(), email: z.string().email() });
export const useUser = createApiHook({
  schema: UserSchema,
  endpoint: ({ id }) => `/api/users/${id}`,
  tags: ['user']
});

// Invalidate by tag
function useInvalidateTag(tag: string) {
  const qc = useQueryClient();
  return () => qc.invalidateQueries({
    predicate: (q) => Array.isArray(q.meta?.tags) && q.meta.tags.includes(tag)
  });
}

