// Composable form primitive with schema + multi-step + draft persistence
function useTypedForm<T extends z.ZodSchema>(schema: T, options?: { persistKey?: string }) {
  const form = useForm<z.infer<T>>({ resolver: zodResolver(schema) });

  // Draft persistence
  useEffect(() => {
    if (!options?.persistKey) return;
    const stored = localStorage.getItem(options.persistKey);
    if (stored) {
      try { form.reset(JSON.parse(stored)); } catch {}
    }
    const sub = form.watch((values) => {
      try { localStorage.setItem(options.persistKey!, JSON.stringify(values)); } catch {}
    });
    return () => sub.unsubscribe();
  }, [options?.persistKey, form]);

  return form;
}

// Server actions + progressive enhancement
function SignupForm() {
  const form = useTypedForm(schema, { persistKey: 'signup-draft' });
  // Standard submit + draft survives reload
  return (
    <form onSubmit={form.handleSubmit(submit)}>
      <Field name='email' label='Email' form={form} />
      <Field name='password' label='Password' type='password' form={form} />
      <button disabled={form.formState.isSubmitting}>Sign up</button>
    </form>
  );
}

