// Imperative API: await dialog.confirm()
import { useState, useEffect, createContext, useContext, ReactNode } from 'react';
import * as Dialog from '@radix-ui/react-dialog';

type DialogConfig = { title: string; message: string; resolve: (ok: boolean) => void };
const DialogCtx = createContext<{ confirm: (msg: string, title?: string) => Promise<boolean> } | null>(null);

export function useDialog() {
  const ctx = useContext(DialogCtx);
  if (!ctx) throw new Error('DialogProvider missing');
  return ctx;
}

export function DialogProvider({ children }: { children: ReactNode }) {
  const [config, setConfig] = useState<DialogConfig | null>(null);

  const confirm = (message: string, title = 'Confirm'): Promise<boolean> => {
    return new Promise(resolve => {
      setConfig({ title, message, resolve });
    });
  };

  return (
    <DialogCtx.Provider value={{ confirm }}>
      {children}
      <Dialog.Root open={!!config} onOpenChange={(o) => { if (!o && config) { config.resolve(false); setConfig(null); } }}>
        {config && (
          <Dialog.Portal>
            <Dialog.Overlay className='fixed inset-0 bg-black/50' />
            <Dialog.Content className='fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-6 rounded-lg max-w-md'>
              <Dialog.Title className='text-lg font-semibold'>{config.title}</Dialog.Title>
              <p className='mt-2 text-sm'>{config.message}</p>
              <div className='mt-6 flex gap-2 justify-end'>
                <button onClick={() => { config.resolve(false); setConfig(null); }} className='px-4 py-2 border rounded'>Cancel</button>
                <button onClick={() => { config.resolve(true); setConfig(null); }} className='px-4 py-2 bg-primary text-white rounded'>OK</button>
              </div>
            </Dialog.Content>
          </Dialog.Portal>
        )}
      </Dialog.Root>
    </DialogCtx.Provider>
  );
}

