// Reversed scroll position (chat anchors at bottom)
import { useReverseScroll } from './hooks';

function ChatList({ messages, onLoadOlder, hasOlder }: Props) {
  const parentRef = useRef<HTMLDivElement>(null);
  const virtualizer = useVirtualizer({
    count: messages.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 60,
    overscan: 5,
    measureElement: (el) => el.getBoundingClientRect().height,
    // Scroll to bottom on initial render
    initialOffset: () => {
      const el = parentRef.current;
      return el ? el.scrollHeight - el.clientHeight : 0;
    }
  });

  // Preserve scroll position when loading older messages
  const prevHeightRef = useRef(0);
  useLayoutEffect(() => {
    const el = parentRef.current;
    if (!el) return;
    const diff = el.scrollHeight - prevHeightRef.current;
    if (diff > 0 && prevHeightRef.current > 0) {
      el.scrollTop += diff;  // maintain visual position when prepending
    }
    prevHeightRef.current = el.scrollHeight;
  }, [messages.length]);

  // Detect scroll up = load older
  useEffect(() => {
    const items = virtualizer.getVirtualItems();
    if (items[0]?.index < 5 && hasOlder) onLoadOlder();
  }, [virtualizer.getVirtualItems(), hasOlder, onLoadOlder]);

  return <div ref={parentRef} role='log' aria-live='polite' aria-relevant='additions' style={{ height: 600, overflowY: 'auto' }}>
    <div style={{ height: virtualizer.getTotalSize(), position: 'relative' }}>
      {virtualizer.getVirtualItems().map(vr => (
        <div
          key={messages[vr.index].id}
          ref={virtualizer.measureElement}
          data-index={vr.index}
          style={{ position: 'absolute', top: 0, transform: `translateY(${vr.start}px)`, width: '100%' }}
        >
          <Message message={messages[vr.index]} />
