// Per-field auto-save with conflict detection via etags
function usePerFieldAutoSave<T extends Record<string, any>>(initial: T, save: (field: keyof T, value: any, etag: string) => Promise<{ etag: string }>) {
  const [data, setData] = useState(initial);
  const [etag, setEtag] = useState('');
  const [fieldStates, setFieldStates] = useState<Record<keyof T, 'idle' | 'saving' | 'saved' | 'conflict'>>({} as any);

  const saveField = useDebouncedCallback(async <K extends keyof T>(field: K, value: T[K]) => {
    setFieldStates(s => ({ ...s, [field]: 'saving' }));
    try {
      const result = await save(field, value, etag);
      setEtag(result.etag);
      setFieldStates(s => ({ ...s, [field]: 'saved' }));
      setTimeout(() => setFieldStates(s => ({ ...s, [field]: 'idle' })), 2000);
    } catch (e) {
      if (e instanceof ConflictError) {
        setFieldStates(s => ({ ...s, [field]: 'conflict' }));
        // Refetch + merge
      }
    }
  }, 500);

  const updateField = <K extends keyof T>(field: K, value: T[K]) => {
    setData(d => ({ ...d, [field]: value }));
    saveField(field, value);
  };

  return { data, updateField, fieldStates };
}
